import{_ as t}from"./chunks/Vulnerability-Disclosure-Jedox-Jedox-04-2023.CIQ4NkLw.js";import{_ as o,o as a,c as r,an as i}from"./chunks/framework.D5fFzH9V.js";const b=JSON.parse('{"title":"Advisories","description":"Security advisories and disclosure reports published by Syslifters","frontmatter":{"description":"Security advisories and disclosure reports published by Syslifters"},"headers":[],"relativePath":"advisories.md","filePath":"advisories.md"}'),s={name:"advisories.md"};function n(l,e,d,c,u,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /advisories.md for this page in Markdown format</div><h1 id="advisories" tabindex="-1">Advisories <a class="header-anchor" href="#advisories" aria-label="Permalink to &quot;Advisories&quot;">â€‹</a></h1><h2 id="jedox-2023" tabindex="-1">Jedox 2023 <a class="header-anchor" href="#jedox-2023" aria-label="Permalink to &quot;Jedox 2023&quot;">â€‹</a></h2><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">â€‹</a></h3><a href="/assets/vulnerability-disclosure/Vulnerability-Disclosure-Jedox-Jedox-04-2023.pdf" target="_blank" rel="noreferrer"><figure class="on-the-fly-behavior" style="float:right;width:30%;margin:0.5em;"><img alt="Vulnerability Disclosure Jedox Preview" src="'+t+'" style="border:1px solid;"><figcaption>Download Report</figcaption></figure></a><ul><li><strong><span class="iconify" data-icon="fa6-solid:computer" aria-hidden="true"></span> Vendor:</strong> <a href="https://www.jedox.com/de/" target="_blank">Jedox GmbH</a></li><li><strong><span class="iconify" data-icon="fa6-brands:product-hunt" aria-hidden="true"></span> Product:</strong> Jedox / Jedox Cloud</li><li><strong><span class="iconify" data-icon="octicon:versions-16" aria-hidden="true"></span> Version:</strong> Jedox 2020.2.5+</li><li><strong><span class="iconify" data-icon="octicon:number-16" aria-hidden="true"></span> CVE Number:</strong> CVE-2022-47874, CVE-2022-47875, CVE-2022-47876, CVE-2022-47877, CVE-2022-47878, CVE-2022-47879, CVE-2022-47880</li></ul><h3 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">â€‹</a></h3><ul><li><strong>2022-12-20:</strong> Initial contact to the vendor via two managers</li><li><strong>2022-12-27:</strong> Contact with vendor via public mail address</li><li><strong>2023-01-11:</strong> Vendor provides encrypted channel for vulnerability information</li><li><strong>2023-01-18:</strong> Reporting of vulnerability details</li><li><strong>2023-04-28:</strong> Planned public disclosure</li></ul><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">â€‹</a></h3><p><strong>CVE-2022-47879: Code Execution via RPC Interfaces</strong><br> A Remote Code Execution (RCE) vulnerability in <em>/be/rpc.php</em> and <em>/be/erpc.php</em> in Jedox Cloud and Jedox 2020.2.5 allows remote authenticated users to load arbitrary PHP classes from the <em>rtn</em> directory and to execute its methods. To exploitthis vulnerability, the attacker needs knowledge about loadable classes, their methods and arguments.</p><p><strong>CVE-2022-47875: Remote Code Execution via Directory Traversal</strong><br> A Directory Traversal vulnerability in <em>/be/erpc.php</em> in Jedox Cloud and Jedox 2020.2.5 allows remote authenticated users to execute arbitrary code. To exploit the vulnerability, the attacker must have the permissions to upload files.</p><p><strong>CVE-2022-47877: Stored Cross-Site Scripting in Log-Module</strong><br> A Stored cross-site scripting vulnerability in Jedox 2020.2.5 allows remote authenticated users to inject arbitrary web scripts or HTML in the logs page via the log module. To exploit the vulnerability, the attacker must append an XSS payloadto the log message.</p><p><strong>CVE-2022-47878: Remote Code Execution via Configurable Storage Path</strong><br> Incorrect input validation for the default-storage-path in the settings page in Jedox 2020.2.5 allows remote, authenticated users to specify the location as web root directory. Consecutive file uploads can lead to the execution of arbitrarycode. To exploit the vulnerability, the attacker sets the default storage path to the web root.</p><p><strong>CVE-2022-47876: Remote Code Execution via Executable Groovy-Scripts</strong><br> Integrator in Jedox 2020.2.5 allows remote authenticated users to create Jobs to execute arbitrary code via Groovy-scripts. To exploit the vulnerability, the attacker must be able to create a Groovy-Job in Integrator.</p><p><strong>CVE-2022-47874: Disclosure of Database Credentials via Improper Access Controls</strong><br> Improper access controls in <em>/tc/rpc</em> in Jedox Cloud and Jedox 2020.2.5 allows remote authenticated users to view details of database connections via the class <em>com.jedox.etl.mngr.Connections</em> and the method <em>getGlobalConnection</em>. To exploitthe vulnerability, the attacker must know the name of the database connection.</p><p><strong>CVE-2022-47880: Disclosure of Database Credentials via Connection Checks</strong><br> An information disclosure vulnerability in <code>/be/rpc.php</code> in Jedox Cloud and Jedox 2020.2.5 allows remote authenticated users with the appropriate permissions to modify database connections to disclose the clear text credentials via the <code>test connection</code>function. To exploit the vulnerability, the attacker must set the host of the database connection to a server under his control.</p>',16)])])}const v=o(s,[["render",n]]);export{b as __pageData,v as default};
